     5→//! Gallops JSON operations
     6→//!
     7→//! Implements read/write operations on the Gallops JSON store.
     8→//! All operations are atomic (write to temp, then rename).
     9→
    10→use serde::{Deserialize, Serialize};
    11→use crate::jjrc_core::jjrc_timestamp_full as timestamp_full;
    12→use crate::jjrf_favor::{JJRF_CHARSET, jjrf_Firemark as Firemark, jjrf_Coronet as Coronet, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX, JJRF_CORONET_PREFIX as CORONET_PREFIX};
    13→use crate::jjrs_steeplechase::jjrs_SteeplechaseEntry as SteeplechaseEntry;
    14→use std::collections::{BTreeMap, HashSet};
    15→use std::fs;
    16→use std::io::{Read as IoRead, Write};
    17→use std::path::Path;
