    44→/// Tack record - snapshot of Pace state and plan
    45→#[derive(Debug, Clone, Serialize, Deserialize)]
    46→pub struct jjrg_Tack {
    47→    pub ts: String,
    48→    pub state: jjrg_PaceState,
    49→    pub text: String,
    50→    pub silks: String,
    51→    pub commit: String,
    52→    #[serde(skip_serializing_if = "Option::is_none")]
    53→    pub direction: Option<String>,
    54→}
    55→
    56→/// Pace record - discrete action within a Heat
    57→///
    58→/// Note: Custom Deserialize implementation handles legacy format migration.
    59→/// Legacy format had `silks` on Pace; canonical format has `silks` on each Tack.
    60→#[derive(Debug, Clone, Serialize)]
    61→pub struct jjrg_Pace {
    62→    pub tacks: Vec<jjrg_Tack>,
    63→}
    64→
    65→impl<'de> serde::Deserialize<'de> for jjrg_Pace {
    66→    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    67→    where
    68→        D: serde::Deserializer<'de>,
    69→    {
    70→        use serde::de::Error;
    71→
    72→        // Deserialize as raw JSON value first
    73→        let raw: serde_json::Value = serde::Deserialize::deserialize(deserializer)?;
    74→
    75→        // Extract legacy silks from pace (if present)
    76→        let pace_silks = raw.get("silks").and_then(|v| v.as_str()).map(String::from);
    77→
    78→        // Extract tacks array
    79→        let tacks_value = raw.get("tacks").ok_or_else(|| D::Error::missing_field("tacks"))?;
    80→        let tacks_array = tacks_value.as_array().ok_or_else(|| D::Error::custom("tacks must be an array"))?;
    81→
    82→        // Process each tack with migration
    83→        let mut tacks = Vec::with_capacity(tacks_array.len());
    84→        for (i, tack_value) in tacks_array.iter().enumerate() {
    85→            let ts = tack_value.get("ts")
    86→                .and_then(|v| v.as_str())
    87→                .ok_or_else(|| D::Error::custom(format!("tacks[{}]: missing ts", i)))?
    88→                .to_string();
    89→
    90→            let state: jjrg_PaceState = tack_value.get("state")
    91→                .ok_or_else(|| D::Error::custom(format!("tacks[{}]: missing state", i)))
    92→                .and_then(|v| serde_json::from_value(v.clone()).map_err(|e| D::Error::custom(format!("tacks[{}]: invalid state: {}", i, e))))?;
    93→
    94→            let text = tack_value.get("text")
    95→                .and_then(|v| v.as_str())
    96→                .ok_or_else(|| D::Error::custom(format!("tacks[{}]: missing text", i)))?
    97→                .to_string();
    98→
    99→            // Migration: silks from tack, or inherit from pace, or error
   100→            let silks = if let Some(s) = tack_value.get("silks").and_then(|v| v.as_str()) {
   101→                s.to_string()
   102→            } else if let Some(ref ps) = pace_silks {
   103→                ps.clone()
   104→            } else {
   105→                return Err(D::Error::custom(format!("tacks[{}]: missing silks and no pace-level silks to inherit", i)));
   106→            };
   107→
   108→            // Migration: commit from tack, or use JJRG_UNKNOWN_COMMIT
   109→            let commit = tack_value.get("commit")
   110→                .and_then(|v| v.as_str())
   111→                .map(String::from)
   112→                .unwrap_or_else(|| JJRG_UNKNOWN_COMMIT.to_string());
   113→
   114→            let direction = tack_value.get("direction")
   115→                .and_then(|v| v.as_str())
   116→                .map(String::from);
   117→
   118→            tacks.push(jjrg_Tack {
   119→                ts,
   120→                state,
   121→                text,
   122→                silks,
   123→                commit,
   124→                direction,
   125→            });
   126→        }
   127→
   128→        Ok(jjrg_Pace { tacks })
   129→    }
   130→}
