   144→/// Root Gallops structure
   145→#[derive(Debug, Clone, Serialize, Deserialize)]
   146→pub struct jjrg_Gallops {
   147→    pub next_heat_seed: String,
   148→    pub heats: BTreeMap<String, jjrg_Heat>,
   149→}
   150→
   151→// Validation helper functions
   152→
   153→/// Check if string contains only URL-safe base64 characters
   154→pub(crate) fn zjjrg_is_base64(s: &str) -> bool {
   155→    s.bytes().all(|b| JJRF_CHARSET.contains(&b))
   156→}
   157→
   158→/// Check if string is valid kebab-case (non-empty, lowercase alphanumeric with hyphens)
   159→pub(crate) fn zjjrg_is_kebab_case(s: &str) -> bool {
   160→    if s.is_empty() {
   161→        return false;
   162→    }
   163→    // Pattern: [a-z0-9]+(-[a-z0-9]+)*
   164→    let parts: Vec<&str> = s.split('-').collect();
   165→    for part in parts {
   166→        if part.is_empty() {
   167→            return false;
   168→        }
   169→        if !part.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit()) {
   170→            return false;
   171→        }
   172→    }
   173→    true
   174→}
   175→
   176→/// Check if string matches YYMMDD format
   177→pub(crate) fn zjjrg_is_yymmdd(s: &str) -> bool {
   178→    if s.len() != 6 {
   179→        return false;
   180→    }
   181→    s.chars().all(|c| c.is_ascii_digit())
   182→}
   183→
   184→/// Check if string matches YYMMDD-HHMM format
   185→pub(crate) fn zjjrg_is_yymmdd_hhmm(s: &str) -> bool {
   186→    if s.len() != 11 {
   187→        return false;
   188→    }
   189→    let parts: Vec<&str> = s.split('-').collect();
   190→    if parts.len() != 2 {
   191→        return false;
   192→    }
   193→    parts[0].len() == 6
   194→        && parts[0].chars().all(|c| c.is_ascii_digit())
   195→        && parts[1].len() == 4
   196→        && parts[1].chars().all(|c| c.is_ascii_digit())
   197→}
   198→
   199→/// Check if string is valid commit SHA format
   200→///
   201→/// Length is derived from JJRG_UNKNOWN_COMMIT constant.
   202→pub(crate) fn zjjrg_is_commit_sha(s: &str) -> bool {
   203→    s.len() == JJRG_UNKNOWN_COMMIT.len() && s.chars().all(|c| c.is_ascii_hexdigit())
   204→}
   205→
   206→impl jjrg_Gallops {
   207→    /// Load Gallops from a file path
   208→    pub fn jjrg_load(path: &Path) -> Result<Self, String> {
   209→        let content = fs::read_to_string(path)
   210→            .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
   211→
   212→        let gallops: jjrg_Gallops = serde_json::from_str(&content)
   213→            .map_err(|e| format!("Failed to parse JSON: {}", e))?;
   214→
   215→        Ok(gallops)
   216→    }
   217→
   218→    /// Save Gallops to a file path (atomic write)
   219→    pub fn jjrg_save(&self, path: &Path) -> Result<(), String> {
   220→        // Serialize to pretty JSON
   221→        let content = serde_json::to_string_pretty(self)
   222→            .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
   223→
   224→        // Create temp file in same directory for atomic rename
   225→        let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
   226→        let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
   227→
   228→        // Write to temp file
   229→        let mut file = fs::File::create(&temp_path)
   230→            .map_err(|e| format!("Failed to create temp file: {}", e))?;
   231→        file.write_all(content.as_bytes())
   232→            .map_err(|e| format!("Failed to write temp file: {}", e))?;
   233→        file.sync_all()
   234→            .map_err(|e| format!("Failed to sync temp file: {}", e))?;
   235→        drop(file);
   236→
   237→        // Atomic rename
   238→        fs::rename(&temp_path, path)
   239→            .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
   240→
   241→        Ok(())
   242→    }
   243→
   244→    /// Validate the Gallops structure
   245→    ///
   246→    /// Returns Ok(()) if valid, Err(Vec<String>) with all validation errors otherwise.
   247→    pub fn jjrg_validate(&self) -> Result<(), Vec<String>> {
   248→        let mut errors = Vec::new();
   249→
   250→        // Rule 1: next_heat_seed must be 2 URL-safe base64 characters
   251→        if self.next_heat_seed.len() != 2 {
   252→            errors.push(format!(
   253→                "next_heat_seed must be 2 characters, got {}",
   254→                self.next_heat_seed.len()
   255→            ));
   256→        } else if !zjjrg_is_base64(&self.next_heat_seed) {
   257→            errors.push(format!(
   258→                "next_heat_seed contains invalid base64 characters: '{}'",
   259→                self.next_heat_seed
   260→            ));
   261→        }
   262→
   263→        // Rule 2: heats object exists (implicitly satisfied by struct)
   264→
   265→        // Validate each Heat
   266→        for (heat_key, heat) in &self.heats {
   267→            self.zjjrg_validate_heat(heat_key, heat, &mut errors);
   268→        }
   269→
   270→        if errors.is_empty() {
   271→            Ok(())
   272→        } else {
   273→            Err(errors)
   274→        }
   275→    }
   276→
   277→    fn zjjrg_validate_heat(&self, heat_key: &str, heat: &jjrg_Heat, errors: &mut Vec<String>) {
   278→        let heat_ctx = format!("Heat '{}'", heat_key);
   279→
   280→        // Rule 3: Heat key must match ₣[A-Za-z0-9_-]{2}
   281→        if !heat_key.starts_with('₣') {
   282→            errors.push(format!("{}: key must start with '₣'", heat_ctx));
   283→        } else {
   284→            let suffix = &heat_key[3..]; // ₣ is 3 bytes in UTF-8
   285→            if suffix.len() != 2 {
   286→                errors.push(format!(
   287→                    "{}: key must have 2 base64 chars after '₣', got {}",
   288→                    heat_ctx,
   289→                    suffix.len()
   290→                ));
   291→            } else if !zjjrg_is_base64(suffix) {
   292→                errors.push(format!(
   293→                    "{}: key contains invalid base64 characters",
   294→                    heat_ctx
   295→                ));
   296→            }
   297→        }
   298→
   299→        // Rule 4: Required Heat fields
   300→        // silks (non-empty kebab-case)
   301→        if !zjjrg_is_kebab_case(&heat.silks) {
   302→            errors.push(format!(
   303→                "{}: silks must be non-empty kebab-case, got '{}'",
   304→                heat_ctx, heat.silks
   305→            ));
   306→        }
   307→
   308→        // creation_time (YYMMDD)
   309→        if !zjjrg_is_yymmdd(&heat.creation_time) {
   310→            errors.push(format!(
   311→                "{}: creation_time must be YYMMDD format, got '{}'",
   312→                heat_ctx, heat.creation_time
   313→            ));
   314→        }
   315→
   316→        // status (validated by serde enum)
   317→
   318→        // next_pace_seed (3 URL-safe base64 characters)
   319→        if heat.next_pace_seed.len() != 3 {
   320→            errors.push(format!(
   321→                "{}: next_pace_seed must be 3 characters, got {}",
   322→                heat_ctx,
   323→                heat.next_pace_seed.len()
   324→            ));
   325→        } else if !zjjrg_is_base64(&heat.next_pace_seed) {
   326→            errors.push(format!(
   327→                "{}: next_pace_seed contains invalid base64 characters",
   328→                heat_ctx
   329→            ));
   330→        }
   331→
   332→        // Extract heat identity (base64 part without prefix) for pace validation
   333→        let heat_identity = if heat_key.starts_with('₣') && heat_key.len() >= 5 {
   334→            Some(&heat_key[3..]) // ₣ is 3 bytes
   335→        } else {
   336→            None
   337→        };
   338→
   339→        // Rule 5: order array and paces object must have identical key sets
   340→        let order_set: HashSet<&String> = heat.order.iter().collect();
   341→        let _paces_set: HashSet<&String> = heat.paces.keys().collect();
   342→
   343→        if order_set.len() != heat.order.len() {
   344→            errors.push(format!("{}: order array contains duplicate entries", heat_ctx));
   345→        }
   346→
   347→        let in_order_not_paces: Vec<_> = heat
   348→            .order
   349→            .iter()
   350→            .filter(|k| !heat.paces.contains_key(*k))
   351→            .collect();
   352→        let in_paces_not_order: Vec<_> = heat
   353→            .paces
   354→            .keys()
   355→            .filter(|k| !order_set.contains(k))
   356→            .collect();
   357→
   358→        if !in_order_not_paces.is_empty() {
   359→            errors.push(format!(
   360→                "{}: order contains keys not in paces: {:?}",
   361→                heat_ctx, in_order_not_paces
   362→            ));
   363→        }
   364→        if !in_paces_not_order.is_empty() {
   365→            errors.push(format!(
   366→                "{}: paces contains keys not in order: {:?}",
   367→                heat_ctx, in_paces_not_order
   368→            ));
   369→        }
   370→
   371→        // Validate each Pace
   372→        for (pace_key, pace) in &heat.paces {
   373→            self.zjjrg_validate_pace(&heat_ctx, heat_identity, pace_key, pace, errors);
   374→        }
   375→    }
   376→
   377→    fn zjjrg_validate_pace(
   378→        &self,
   379→        heat_ctx: &str,
   380→        heat_identity: Option<&str>,
   381→        pace_key: &str,
   382→        pace: &jjrg_Pace,
   383→        errors: &mut Vec<String>,
   384→    ) {
   385→        let pace_ctx = format!("{} Pace '{}'", heat_ctx, pace_key);
   386→
   387→        // Rule 6: Pace key must match ₢[A-Za-z0-9_-]{5}
   388→        if !pace_key.starts_with('₢') {
   389→            errors.push(format!("{}: key must start with '₢'", pace_ctx));
   390→        } else {
   391→            let suffix = &pace_key[3..]; // ₢ is 3 bytes in UTF-8
   392→            if suffix.len() != 5 {
   393→                errors.push(format!(
   394→                    "{}: key must have 5 base64 chars after '₢', got {}",
   395→                    pace_ctx,
   396→                    suffix.len()
   397→                ));
   398→            } else {
   399→                if !zjjrg_is_base64(suffix) {
   400→                    errors.push(format!(
   401→                        "{}: key contains invalid base64 characters",
   402→                        pace_ctx
   403→                    ));
   404→                }
   405→                // Pace must embed parent Heat identity (first 2 chars)
   406→                if let Some(heat_id) = heat_identity {
   407→                    if !suffix.starts_with(heat_id) {
   408→                        errors.push(format!(
   409→                            "{}: key must embed parent heat identity '{}', got '{}'",
   410→                            pace_ctx,
   411→                            heat_id,
   412→                            &suffix[..2.min(suffix.len())]
   413→                        ));
   414→                    }
   415→                }
   416→            }
   417→        }
   418→
   419→        // Rule 7: tacks must be non-empty array
   420→        if pace.tacks.is_empty() {
   421→            errors.push(format!("{}: tacks array must not be empty", pace_ctx));
   422→        }
   423→
   424→        // Validate each Tack
   425→        for (i, tack) in pace.tacks.iter().enumerate() {
   426→            self.zjjrg_validate_tack(&pace_ctx, i, tack, errors);
   427→        }
   428→    }
   429→
   430→    fn zjjrg_validate_tack(&self, pace_ctx: &str, index: usize, tack: &jjrg_Tack, errors: &mut Vec<String>) {
   431→        let tack_ctx = format!("{} Tack[{}]", pace_ctx, index);
   432→
   433→        // Rule 8: ts must be YYMMDD-HHMM
   434→        if !zjjrg_is_yymmdd_hhmm(&tack.ts) {
   435→            errors.push(format!(
   436→                "{}: ts must be YYMMDD-HHMM format, got '{}'",
   437→                tack_ctx, tack.ts
   438→            ));
   439→        }
   440→
   441→        // Rule 8: text must be non-empty
   442→        if tack.text.is_empty() {
   443→            errors.push(format!("{}: text must not be empty", tack_ctx));
   444→        }
   445→
   446→        // Rule 8: silks must be non-empty kebab-case
   447→        if !zjjrg_is_kebab_case(&tack.silks) {
   448→            errors.push(format!(
   449→                "{}: silks must be non-empty kebab-case, got '{}'",
   450→                tack_ctx, tack.silks
   451→            ));
   452→        }
   453→
   454→        // Rule 8: commit must be valid format (7 hex chars)
   455→        if !zjjrg_is_commit_sha(&tack.commit) {
   456→            errors.push(format!(
   457→                "{}: commit must be 7 hex characters, got '{}'",
   458→                tack_ctx, tack.commit
   459→            ));
   460→        }
   461→
   462→        // Rule 9: direction presence depends on state
   463→        match tack.state {
   464→            jjrg_PaceState::Bridled => {
   465→                match &tack.direction {
   466→                    None => {
   467→                        errors.push(format!(
   468→                            "{}: direction is required when state is 'bridled'",
   469→                            tack_ctx
   470→                        ));
   471→                    }
   472→                    Some(d) if d.is_empty() => {
   473→                        errors.push(format!(
   474→                            "{}: direction must not be empty when state is 'bridled'",
   475→                            tack_ctx
   476→                        ));
   477→                    }
   478→                    _ => {}
   479→                }
   480→            }
   481→            _ => {
   482→                if tack.direction.is_some() {
   483→                    errors.push(format!(
   484→                        "{}: direction must be absent when state is not 'bridled'",
   485→                        tack_ctx
   486→                    ));
   487→                }
   488→            }
   489→        }
   490→    }
   491→}
