   493→// ===== Seed Increment Helpers =====
   494→
   495→/// Increment a base64 seed string (with carry)
   496→/// Works for both 2-char (heat) and 3-char (pace) seeds
   497→pub(crate) fn zjjrg_increment_seed(seed: &str) -> String {
   498→    let mut chars: Vec<u8> = seed.bytes().collect();
   499→    let mut carry = true;
   500→
   501→    // Process from right to left
   502→    for i in (0..chars.len()).rev() {
   503→        if !carry {
   504→            break;
   505→        }
   506→
   507→        // Find current position in charset
   508→        let pos = JJRF_CHARSET.iter().position(|&c| c == chars[i]).unwrap_or(0);
   509→
   510→        if pos == 63 {
   511→            // Wrap around
   512→            chars[i] = JJRF_CHARSET[0];
   513→            // carry remains true
   514→        } else {
   515→            chars[i] = JJRF_CHARSET[pos + 1];
   516→            carry = false;
   517→        }
   518→    }
   519→
   520→    String::from_utf8(chars).unwrap_or_else(|_| seed.to_string())
   521→}
   522→
   523→/// Capture current commit SHA
   524→///
   525→/// Runs `git rev-parse --short=N HEAD` where N is derived from JJRG_UNKNOWN_COMMIT length.
   526→/// Returns JJRG_UNKNOWN_COMMIT on error (e.g., not in a git repo).
   527→pub fn jjrg_capture_commit_sha() -> String {
   528→    use std::process::Command;
   529→
   530→    let short_arg = format!("--short={}", JJRG_UNKNOWN_COMMIT.len());
   531→    match Command::new("git")
   532→        .args(["rev-parse", &short_arg, "HEAD"])
   533→        .output()
   534→    {
   535→        Ok(output) if output.status.success() => {
   536→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   537→        }
   538→        _ => JJRG_UNKNOWN_COMMIT.to_string(),
   539→    }
   540→}
