   542→/// Create a new Tack with current timestamp and commit SHA
   543→///
   544→/// Centralizes Tack creation to ensure consistent timestamp/commit capture.
   545→/// All code creating new Tacks should use this helper.
   546→pub fn jjrg_make_tack(
   547→    state: jjrg_PaceState,
   548→    text: String,
   549→    silks: String,
   550→    direction: Option<String>,
   551→) -> jjrg_Tack {
   552→    jjrg_Tack {
   553→        ts: timestamp_full(),
   554→        state,
   555→        text,
   556→        silks,
   557→        commit: jjrg_capture_commit_sha(),
   558→        direction,
   559→    }
   560→}
