   666→impl jjrg_Gallops {
   667→    /// Nominate a new Heat
   668→    ///
   669→    /// Creates a new Heat with empty Pace structure and creates the paddock file.
   670→    pub fn jjrg_nominate(&mut self, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
   671→        // Validate silks is kebab-case
   672→        if !zjjrg_is_kebab_case(&args.silks) {
   673→            return Err(format!("silks must be kebab-case, got '{}'", args.silks));
   674→        }
   675→
   676→        // Validate created is YYMMDD
   677→        if !zjjrg_is_yymmdd(&args.created) {
   678→            return Err(format!("created must be YYMMDD format, got '{}'", args.created));
   679→        }
   680→
   681→        // Allocate Firemark from next_heat_seed
   682→        let firemark_str = format!("{}{}", FIREMARK_PREFIX, self.next_heat_seed);
   683→        let heat_id = self.next_heat_seed.clone();
   684→
   685→        // Compute paddock path
   686→        let paddock_file = format!(".claude/jjm/jjp_{}.md", heat_id);
   687→
   688→        // Create paddock file with template
   689→        let paddock_path = base_path.join(&paddock_file);
   690→        if let Some(parent) = paddock_path.parent() {
   691→            fs::create_dir_all(parent)
   692→                .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
   693→        }
   694→
   695→        let paddock_content = format!(
   696→            "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
   697→            args.silks
   698→        );
   699→
   700→        fs::write(&paddock_path, paddock_content)
   701→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   702→
   703→        // Create new Heat
   704→        let heat = jjrg_Heat {
   705→            silks: args.silks,
   706→            creation_time: args.created,
   707→            status: jjrg_HeatStatus::Current,
   708→            order: Vec::new(),
   709→            next_pace_seed: "AAA".to_string(),
   710→            paddock_file,
   711→            paces: BTreeMap::new(),
   712→        };
   713→
   714→        // Insert Heat
   715→        self.heats.insert(firemark_str.clone(), heat);
   716→
   717→        // Increment next_heat_seed
   718→        self.next_heat_seed = zjjrg_increment_seed(&self.next_heat_seed);
   719→
   720→        Ok(jjrg_NominateResult { firemark: firemark_str })
   721→    }
   722→
   723→    /// Slate a new Pace
   724→    ///
   725→    /// Adds a new Pace to a Heat with an initial Tack in rough state.
   726→    /// Positioning: use before/after/first to insert at specific location.
   727→    pub fn jjrg_slate(&mut self, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
   728→        // Validate silks is kebab-case
   729→        if !zjjrg_is_kebab_case(&args.silks) {
   730→            return Err(format!("silks must be kebab-case, got '{}'", args.silks));
   731→        }
   732→
   733→        // Validate text is non-empty
   734→        if args.text.is_empty() {
   735→            return Err("text must not be empty".to_string());
   736→        }
   737→
   738→        // Validate positioning mutual exclusivity
   739→        let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   740→            .iter()
   741→            .filter(|&&x| x)
   742→            .count();
   743→        if position_count > 1 {
   744→            return Err("Only one of --before, --after, or --first may be specified".to_string());
   745→        }
   746→
   747→        // Parse and normalize firemark
   748→        let firemark = Firemark::jjrf_parse(&args.firemark)
   749→            .map_err(|e| format!("Invalid firemark: {}", e))?;
   750→        let firemark_key = firemark.jjrf_display();
   751→
   752→        // Verify Heat exists
   753→        let heat = self.heats.get_mut(&firemark_key)
   754→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   755→
   756→        // If --before or --after specified, validate target coronet exists
   757→        let insert_position = if let Some(ref before_str) = args.before {
   758→            let target = Coronet::jjrf_parse(before_str)
   759→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   760→            let target_key = target.jjrf_display();
   761→            let pos = heat.order.iter().position(|c| c == &target_key)
   762→                .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   763→            Some(pos) // Insert before this position
   764→        } else if let Some(ref after_str) = args.after {
   765→            let target = Coronet::jjrf_parse(after_str)
   766→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   767→            let target_key = target.jjrf_display();
   768→            let pos = heat.order.iter().position(|c| c == &target_key)
   769→                .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   770→            Some(pos + 1) // Insert after this position
   771→        } else if args.first {
   772→            Some(0) // Insert at beginning
   773→        } else {
   774→            None // Append to end (default)
   775→        };
   776→
   777→        // Construct Coronet
   778→        let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
   779→
   780→        // Create initial Tack and Pace
   781→        let tack = jjrg_make_tack(
   782→            jjrg_PaceState::Rough,
   783→            args.text,
   784→            args.silks,
   785→            None,
   786→        );
   787→        let pace = jjrg_Pace {
   788→            tacks: vec![tack],
   789→        };
   790→
   791→        // Insert into order at determined position
   792→        match insert_position {
   793→            Some(pos) => heat.order.insert(pos, coronet_str.clone()),
   794→            None => heat.order.push(coronet_str.clone()),
   795→        }
   796→        heat.paces.insert(coronet_str.clone(), pace);
   797→
   798→        // Increment next_pace_seed
   799→        heat.next_pace_seed = zjjrg_increment_seed(&heat.next_pace_seed);
   800→
   801→        Ok(jjrg_SlateResult { coronet: coronet_str })
   802→    }
   803→
   804→    /// Rail - reorder Paces within a Heat
   805→    ///
   806→    /// Supports two modes:
   807→    /// - Order mode: replace entire sequence with provided order array
   808→    /// - Move mode: relocate a single pace using positioning flags
   809→    pub fn jjrg_rail(&mut self, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
   810→        // Parse and normalize firemark
   811→        let firemark = Firemark::jjrf_parse(&args.firemark)
   812→            .map_err(|e| format!("Invalid firemark: {}", e))?;
   813→        let firemark_key = firemark.jjrf_display();
   814→
   815→        // Verify Heat exists
   816→        let heat = self.heats.get_mut(&firemark_key)
   817→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   818→
   819→        // Mode detection: if move_coronet present, use move mode
   820→        if let Some(ref move_str) = args.move_coronet {
   821→            // Move mode validation
   822→            if !args.order.is_empty() {
   823→                return Err("Cannot combine --move with positional coronets".to_string());
   824→            }
   825→
   826→            // Parse and normalize move coronet
   827→            let move_coronet = Coronet::jjrf_parse(move_str)
   828→                .map_err(|e| format!("Invalid --move coronet: {}", e))?;
   829→            let move_key = move_coronet.jjrf_display();
   830→
   831→            // Validate move coronet exists in heat
   832→            if !heat.paces.contains_key(&move_key) {
   833→                return Err(format!("Pace {} not found in heat {}", move_key, firemark_key));
   834→            }
   835→
   836→            // Count positioning flags
   837→            let position_count = [
   838→                args.before.is_some(),
   839→                args.after.is_some(),
   840→                args.first,
   841→                args.last,
   842→            ].iter().filter(|&&x| x).count();
   843→
   844→            if position_count == 0 {
   845→                return Err("Move mode requires exactly one positioning flag".to_string());
   846→            }
   847→            if position_count > 1 {
   848→                let mut flags = Vec::new();
   849→                if args.before.is_some() { flags.push("--before"); }
   850→                if args.after.is_some() { flags.push("--after"); }
   851→                if args.first { flags.push("--first"); }
   852→                if args.last { flags.push("--last"); }
   853→                return Err(format!("Conflicting positioning flags: {}", flags.join(", ")));
   854→            }
   855→
   856→            // Determine target position and validate
   857→            let current_pos = heat.order.iter().position(|c| c == &move_key)
   858→                .ok_or_else(|| format!("Pace {} not in order array", move_key))?;
   859→
   860→            let new_pos = if args.first {
   861→                // Find first actionable pace (rough or bridled)
   862→                // If none found, use end of array (nothing actionable to precede)
   863→                let first_actionable_idx = heat.order.iter().position(|coronet| {
   864→                    if let Some(pace) = heat.paces.get(coronet) {
   865→                        if let Some(tack) = pace.tacks.first() {
   866→                            matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   867→                        } else {
   868→                            false
   869→                        }
   870→                    } else {
   871→                        false
   872→                    }
   873→                });
   874→                // Use len() as fallback so adjustment logic works correctly for "end" position
   875→                let target_idx = first_actionable_idx.unwrap_or(heat.order.len());
   876→                // If moving from before target, the target shifts down after removal
   877→                if current_pos < target_idx {
   878→                    target_idx - 1
   879→                } else {
   880→                    target_idx
   881→                }
   882→            } else if args.last {
   883→                heat.order.len() - 1
   884→            } else if let Some(ref before_str) = args.before {
   885→                let target = Coronet::jjrf_parse(before_str)
   886→                    .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   887→                let target_key = target.jjrf_display();
   888→
   889→                if target_key == move_key {
   890→                    return Err("Cannot position pace relative to itself".to_string());
   891→                }
   892→
   893→                let target_pos = heat.order.iter().position(|c| c == &target_key)
   894→                    .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   895→
   896→                // If moving from before target, the target shifts down after removal
   897→                if current_pos < target_pos {
   898→                    target_pos - 1
   899→                } else {
   900→                    target_pos
   901→                }
   902→            } else if let Some(ref after_str) = args.after {
   903→                let target = Coronet::jjrf_parse(after_str)
   904→                    .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   905→                let target_key = target.jjrf_display();
   906→
   907→                if target_key == move_key {
   908→                    return Err("Cannot position pace relative to itself".to_string());
   909→                }
   910→
   911→                let target_pos = heat.order.iter().position(|c| c == &target_key)
   912→                    .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   913→
   914→                // If moving from before target, the target shifts down after removal
   915→                if current_pos < target_pos {
   916→                    target_pos // After removal, target is at target_pos-1, we want target_pos-1+1 = target_pos
   917→                } else {
   918→                    target_pos + 1
   919→                }
   920→            } else {
   921→                unreachable!()
   922→            };
   923→
   924→            // Remove from current position and insert at new position
   925→            heat.order.remove(current_pos);
   926→            heat.order.insert(new_pos, move_key);
   927→
   928→        } else {
   929→            // Order mode: replace entire sequence
   930→
   931→            // Normalize the input order (add prefix if missing)
   932→            let normalized_order: Result<Vec<String>, String> = args.order.iter()
   933→                .map(|c| {
   934→                    let coronet = Coronet::jjrf_parse(c)
   935→                        .map_err(|e| format!("Invalid coronet '{}': {}", c, e))?;
   936→                    Ok(coronet.jjrf_display())
   937→                })
   938→                .collect();
   939→            let new_order = normalized_order?;
   940→
   941→            // Validate count matches
   942→            if new_order.len() != heat.order.len() {
   943→                return Err(format!(
   944→                    "Order count mismatch: got {}, expected {}",
   945→                    new_order.len(),
   946→                    heat.order.len()
   947→                ));
   948→            }
   949→
   950→            // Validate no duplicates
   951→            let new_set: HashSet<&String> = new_order.iter().collect();
   952→            if new_set.len() != new_order.len() {
   953→                return Err("Order contains duplicate Coronets".to_string());
   954→            }
   955→
   956→            // Validate all Coronets exist in paces
   957→            for coronet in &new_order {
   958→                if !heat.paces.contains_key(coronet) {
   959→                    return Err(format!("Coronet '{}' not found in Heat's paces", coronet));
   960→                }
   961→            }
   962→
   963→            // Validate all Coronets embed correct parent Firemark
   964→            for coronet in &new_order {
   965→                let c = Coronet::jjrf_parse(coronet).unwrap();
   966→                if c.jjrf_parent_firemark().jjrf_display() != firemark_key {
   967→                    return Err(format!(
   968→                        "Coronet '{}' does not embed parent Heat '{}'",
   969→                        coronet, firemark_key
   970→                    ));
   971→                }
   972→            }
   973→
   974→            // Replace order
   975→            heat.order = new_order;
   976→        }
   977→
   978→        // Return the new order
   979→        Ok(heat.order.clone())
   980→    }
   981→
   982→    /// Tally - add a new Tack to a Pace
   983→    ///
   984→    /// Prepends a new Tack with state transition and/or plan refinement.
   985→    pub fn jjrg_tally(&mut self, args: jjrg_TallyArgs) -> Result<(), String> {
   986→        // Parse and normalize coronet
   987→        let coronet = Coronet::jjrf_parse(&args.coronet)
   988→            .map_err(|e| format!("Invalid coronet: {}", e))?;
   989→        let coronet_key = coronet.jjrf_display();
   990→
   991→        // Extract parent Firemark
   992→        let firemark = coronet.jjrf_parent_firemark();
   993→        let firemark_key = firemark.jjrf_display();
   994→
   995→        // Verify Heat exists
   996→        let heat = self.heats.get_mut(&firemark_key)
   997→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   998→
   999→        // Verify Pace exists
  1000→        let pace = heat.paces.get_mut(&coronet_key)
  1001→            .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
  1002→
  1003→        // Read current Tack
  1004→        let current_tack = pace.tacks.first()
  1005→            .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
  1006→
  1007→        // Determine new state
  1008→        let new_state = args.state.clone().unwrap_or_else(|| current_tack.state.clone());
  1009→
  1010→        // Determine new direction
  1011→        let new_direction = match (&args.state, &new_state) {
  1012→            // State explicitly set to bridled: direction required
  1013→            (Some(jjrg_PaceState::Bridled), _) => {
  1014→                match &args.direction {
  1015→                    Some(d) if !d.is_empty() => Some(d.clone()),
  1016→                    Some(_) => return Err("direction must not be empty when state is bridled".to_string()),
  1017→                    None => return Err("direction is required when state is bridled".to_string()),
  1018→                }
  1019→            }
  1020→            // State explicitly set to something other than bridled: direction forbidden
  1021→            (Some(_), _) => {
  1022→                if args.direction.is_some() {
  1023→                    return Err("direction must be absent when state is not bridled".to_string());
  1024→                }
  1025→                None
  1026→            }
  1027→            // State inherited and was bridled: inherit direction
  1028→            (None, jjrg_PaceState::Bridled) => {
  1029→                args.direction.or_else(|| current_tack.direction.clone())
  1030→            }
  1031→            // State inherited and was not bridled: no direction
  1032→            (None, _) => None,
  1033→        };
  1034→
  1035→        // Determine new text
  1036→        let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
  1037→        if new_text.is_empty() {
  1038→            return Err("text must not be empty".to_string());
  1039→        }
  1040→
  1041→        // Create new Tack (inheriting silks from current tack)
  1042→        let new_tack = jjrg_make_tack(
  1043→            new_state,
  1044→            new_text,
  1045→            current_tack.silks.clone(),
  1046→            new_direction,
  1047→        );
  1048→
  1049→        // Prepend to tacks array
  1050→        pace.tacks.insert(0, new_tack);
  1051→
  1052→        Ok(())
  1053→    }
  1054→
  1055→    /// Draft - move a Pace from one Heat to another
  1056→    ///
  1057→    /// Moves the pace to the destination heat with a new Coronet.
  1058→    /// All Tack history is preserved, with a new Tack recording the draft.
  1059→    /// State is NOT changed - draft is a move operation, not a state transition.
  1060→    pub fn jjrg_draft(&mut self, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
  1061→        // Validate positioning mutual exclusivity
  1062→        let position_count = [args.before.is_some(), args.after.is_some(), args.first]
  1063→            .iter()
  1064→            .filter(|&&x| x)
  1065→            .count();
  1066→        if position_count > 1 {
  1067→            return Err("Only one of --before, --after, or --first may be specified".to_string());
  1068→        }
  1069→
  1070→        // Parse and normalize source coronet
  1071→        let source_coronet = Coronet::jjrf_parse(&args.coronet)
  1072→            .map_err(|e| format!("Invalid coronet: {}", e))?;
  1073→        let source_coronet_key = source_coronet.jjrf_display();
  1074→
  1075→        // Extract source Firemark from coronet
  1076→        let source_firemark = source_coronet.jjrf_parent_firemark();
  1077→        let source_firemark_key = source_firemark.jjrf_display();
  1078→
  1079→        // Parse and normalize destination firemark
  1080→        let dest_firemark = Firemark::jjrf_parse(&args.to)
  1081→            .map_err(|e| format!("Invalid destination firemark: {}", e))?;
  1082→        let dest_firemark_key = dest_firemark.jjrf_display();
  1083→
  1084→        // Validate source and destination are different
  1085→        if source_firemark_key == dest_firemark_key {
  1086→            return Err("Cannot draft pace to same heat".to_string());
  1087→        }
  1088→
  1089→        // Verify source heat exists
  1090→        if !self.heats.contains_key(&source_firemark_key) {
  1091→            return Err(format!("Source heat '{}' not found", source_firemark_key));
  1092→        }
  1093→
  1094→        // Verify destination heat exists
  1095→        if !self.heats.contains_key(&dest_firemark_key) {
  1096→            return Err(format!("Heat '{}' not found", dest_firemark_key));
  1097→        }
  1098→
  1099→        // Verify pace exists in source heat
  1100→        {
  1101→            let source_heat = self.heats.get(&source_firemark_key).unwrap();
  1102→            if !source_heat.paces.contains_key(&source_coronet_key) {
  1103→                return Err(format!("Pace {} not found in heat {}", source_coronet_key, source_firemark_key));
  1104→            }
  1105→        }
  1106→
  1107→        // Validate positioning target if specified
  1108→        let insert_position = if let Some(ref before_str) = args.before {
  1109→            let target = Coronet::jjrf_parse(before_str)
  1110→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
  1111→            let target_key = target.jjrf_display();
  1112→            let dest_heat = self.heats.get(&dest_firemark_key).unwrap();
  1113→            let pos = dest_heat.order.iter().position(|c| c == &target_key)
  1114→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
  1115→            Some(pos)
  1116→        } else if let Some(ref after_str) = args.after {
  1117→            let target = Coronet::jjrf_parse(after_str)
  1118→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
  1119→            let target_key = target.jjrf_display();
  1120→            let dest_heat = self.heats.get(&dest_firemark_key).unwrap();
  1121→            let pos = dest_heat.order.iter().position(|c| c == &target_key)
  1122→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
  1123→            Some(pos + 1)
  1124→        } else if args.first {
  1125→            Some(0)
  1126→        } else {
  1127→            None // Append to end
  1128→        };
  1129→
  1130→        // Remove pace from source heat
  1131→        let source_heat = self.heats.get_mut(&source_firemark_key).unwrap();
  1132→        let pace_data = source_heat.paces.remove(&source_coronet_key)
  1133→            .ok_or_else(|| format!("Pace {} not found", source_coronet_key))?;
  1134→        source_heat.order.retain(|c| c != &source_coronet_key);
  1135→
  1136→        // Get destination heat and allocate new coronet
  1137→        let dest_heat = self.heats.get_mut(&dest_firemark_key).unwrap();
  1138→        let new_coronet_str = format!("{}{}{}", CORONET_PREFIX, dest_firemark.jjrf_as_str(), dest_heat.next_pace_seed);
  1139→
  1140→        // Create new tack recording the draft
  1141→        let first_tack = pace_data.tacks.first();
  1142→        let draft_note = format!("Drafted from {} in {}.\n\n{}",
  1143→            source_coronet_key, source_firemark_key,
  1144→            first_tack.map(|t| t.text.as_str()).unwrap_or(""));
  1145→
  1146→        let draft_tack = jjrg_make_tack(
  1147→            first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough),
  1148→            draft_note,
  1149→            first_tack.map(|t| t.silks.clone()).unwrap_or_default(),
  1150→            first_tack.and_then(|t| t.direction.clone()),
  1151→        );
  1152→
  1153→        // Build new pace with draft tack prepended
  1154→        let mut new_tacks = vec![draft_tack];
  1155→        new_tacks.extend(pace_data.tacks);
  1156→
  1157→        let new_pace = jjrg_Pace {
  1158→            tacks: new_tacks,
  1159→        };
  1160→
  1161→        // Insert into destination heat
  1162→        match insert_position {
  1163→            Some(pos) => dest_heat.order.insert(pos, new_coronet_str.clone()),
  1164→            None => dest_heat.order.push(new_coronet_str.clone()),
  1165→        }
  1166→        dest_heat.paces.insert(new_coronet_str.clone(), new_pace);
  1167→
  1168→        // Increment destination seed
  1169→        dest_heat.next_pace_seed = zjjrg_increment_seed(&dest_heat.next_pace_seed);
  1170→
  1171→        Ok(jjrg_DraftResult { new_coronet: new_coronet_str })
  1172→    }
  1173→
  1174→    /// Retire a Heat
  1175→    ///
  1176→    /// Creates trophy file, removes heat from gallops, deletes paddock file.
  1177→    /// Does NOT save gallops or commit - caller is responsible for that.
  1178→    pub fn jjrg_retire(
  1179→        &mut self,
  1180→        args: jjrg_RetireArgs,
  1181→        base_path: &Path,
  1182→        steeplechase: &[SteeplechaseEntry],
  1183→    ) -> Result<jjrg_RetireResult, String> {
  1184→        // Parse and normalize firemark
  1185→        let firemark = Firemark::jjrf_parse(&args.firemark)
  1186→            .map_err(|e| format!("Invalid firemark: {}", e))?;
  1187→        let firemark_key = firemark.jjrf_display();
  1188→
  1189→        // Validate today is YYMMDD
  1190→        if !zjjrg_is_yymmdd(&args.today) {
  1191→            return Err(format!("today must be YYMMDD format, got '{}'", args.today));
  1192→        }
  1193→
  1194→        // Verify heat exists
  1195→        let heat = self.heats.get(&firemark_key)
  1196→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
  1197→
  1198→        // Read paddock content before we remove anything
  1199→        let paddock_path = base_path.join(&heat.paddock_file);
  1200→        let paddock_content = fs::read_to_string(&paddock_path)
  1201→            .map_err(|e| format!("Failed to read paddock file '{}': {}", heat.paddock_file, e))?;
  1202→
  1203→        // Build trophy content
  1204→        let trophy_content = self.zjjrg_build_trophy_content(&firemark_key, heat, &paddock_content, &args.today, steeplechase)?;
  1205→
  1206→        // Compute trophy path: .claude/jjm/retired/jjh_<created>-r<today>-<silks>.md
  1207→        let trophy_filename = format!(
  1208→            "jjh_{}-r{}-{}.md",
  1209→            heat.creation_time,
  1210→            args.today,
  1211→            heat.silks
  1212→        );
  1213→        let trophy_rel_path = format!(".claude/jjm/retired/{}", trophy_filename);
  1214→        let trophy_full_path = base_path.join(&trophy_rel_path);
  1215→
  1216→        // Create retired directory if needed
  1217→        if let Some(parent) = trophy_full_path.parent() {
  1218→            fs::create_dir_all(parent)
  1219→                .map_err(|e| format!("Failed to create retired directory: {}", e))?;
  1220→        }
  1221→
  1222→        // Write trophy file
  1223→        fs::write(&trophy_full_path, trophy_content)
  1224→            .map_err(|e| format!("Failed to write trophy file: {}", e))?;
  1225→
  1226→        // Capture info for result before removing heat
  1227→        let silks = heat.silks.clone();
  1228→        let paddock_file = heat.paddock_file.clone();
  1229→
  1230→        // Remove heat from gallops (do NOT change next_heat_seed)
  1231→        self.heats.remove(&firemark_key);
  1232→
  1233→        // Delete paddock file
  1234→        if paddock_path.exists() {
  1235→            fs::remove_file(&paddock_path)
  1236→                .map_err(|e| format!("Failed to delete paddock file: {}", e))?;
  1237→        }
  1238→
  1239→        Ok(jjrg_RetireResult {
  1240→            trophy_path: trophy_rel_path,
  1241→            paddock_path: paddock_file,
  1242→            silks,
  1243→            firemark: firemark_key,
  1244→        })
  1245→    }
  1246→
  1247→    /// Build trophy markdown preview (dry-run, no file modifications)
  1248→    ///
  1249→    /// Returns the markdown content that would be written to the trophy file.
  1250→    pub fn jjrg_build_trophy_preview(
  1251→        &self,
  1252→        firemark: &str,
  1253→        paddock_content: &str,
  1254→        today: &str,
  1255→        steeplechase: &[SteeplechaseEntry],
  1256→    ) -> Result<String, String> {
  1257→        // Parse and normalize firemark
  1258→        let fm = Firemark::jjrf_parse(firemark)
  1259→            .map_err(|e| format!("Invalid firemark: {}", e))?;
  1260→        let firemark_key = fm.jjrf_display();
  1261→
  1262→        // Verify heat exists
  1263→        let heat = self.heats.get(&firemark_key)
  1264→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
  1265→
  1266→        self.zjjrg_build_trophy_content(&firemark_key, heat, paddock_content, today, steeplechase)
  1267→    }
  1268→
  1269→    /// Build trophy markdown content
  1270→    fn zjjrg_build_trophy_content(
  1271→        &self,
  1272→        firemark_key: &str,
  1273→        heat: &jjrg_Heat,
  1274→        paddock_content: &str,
  1275→        today: &str,
  1276→        steeplechase: &[SteeplechaseEntry],
  1277→    ) -> Result<String, String> {
  1278→        let mut content = String::new();
  1279→
  1280→        // Header
  1281→        content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
  1282→        content.push_str(&format!("**Firemark:** {}\n", firemark_key));
  1283→        content.push_str(&format!("**Created:** {}\n", heat.creation_time));
  1284→        content.push_str(&format!("**Retired:** {}\n", today));
  1285→        content.push_str("**Status:** retired\n\n");
  1286→
  1287→        // Paddock
  1288→        content.push_str("## Paddock\n\n");
  1289→        content.push_str(paddock_content);
  1290→        if !paddock_content.ends_with('\n') {
  1291→            content.push('\n');
  1292→        }
  1293→        content.push('\n');
  1294→
  1295→        // Paces (in order)
  1296→        content.push_str("## Paces\n\n");
  1297→        for coronet_key in &heat.order {
  1298→            if let Some(pace) = heat.paces.get(coronet_key) {
  1299→                // Get final state from most recent tack
  1300→                let final_state = pace.tacks.first()
  1301→                    .map(|t| match t.state {
  1302→                        jjrg_PaceState::Rough => "rough",
  1303→                        jjrg_PaceState::Bridled => "bridled",
  1304→                        jjrg_PaceState::Complete => "complete",
  1305→                        jjrg_PaceState::Abandoned => "abandoned",
  1306→                    })
  1307→                    .unwrap_or("unknown");
  1308→
  1309→                let pace_silks = pace.tacks.first()
  1310→                    .map(|t| t.silks.as_str())
  1311→                    .unwrap_or("unknown");
  1312→
  1313→                content.push_str(&format!(
  1314→                    "### {} ({}) [{}]\n\n",
  1315→                    pace_silks, coronet_key, final_state
  1316→                ));
  1317→
  1318→                // Tack history (newest first, as stored)
  1319→                for tack in &pace.tacks {
  1320→                    let state_str = match tack.state {
  1321→                        jjrg_PaceState::Rough => "rough",
  1322→                        jjrg_PaceState::Bridled => "bridled",
  1323→                        jjrg_PaceState::Complete => "complete",
  1324→                        jjrg_PaceState::Abandoned => "abandoned",
  1325→                    };
  1326→                    content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
  1327→                    content.push_str(&tack.text);
  1328→                    if !tack.text.ends_with('\n') {
  1329→                        content.push('\n');
  1330→                    }
  1331→                    if let Some(ref direction) = tack.direction {
  1332→                        content.push_str(&format!("\n*Direction:* {}\n", direction));
  1333→                    }
  1334→                    content.push('\n');
  1335→                }
  1336→            }
  1337→        }
  1338→
  1339→        // Steeplechase (newest first, as provided)
  1340→        content.push_str("## Steeplechase\n\n");
  1341→        if steeplechase.is_empty() {
  1342→            content.push_str("(no entries)\n\n");
  1343→        } else {
  1344→            for entry in steeplechase {
  1345→                // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
  1346→                let identity = entry.coronet.as_deref().unwrap_or("Heat");
  1347→                let action = entry.action.as_deref().unwrap_or("notch");
  1348→                content.push_str(&format!(
  1349→                    "### {} - {} - {}\n\n",
  1350→                    entry.timestamp, identity, action
  1351→                ));
  1352→                content.push_str(&entry.subject);
  1353→                if !entry.subject.ends_with('\n') {
  1354→                    content.push('\n');
  1355→                }
  1356→                content.push('\n');
  1357→            }
  1358→        }
  1359→
  1360→        Ok(content)
  1361→    }
  1362→}
  1363→
  1364→/// Read text from stdin (for CLI commands)
  1365→pub fn jjrg_read_stdin() -> Result<String, String> {
  1366→    let mut buffer = String::new();
  1367→    std::io::stdin().read_to_string(&mut buffer)
  1368→        .map_err(|e| format!("Failed to read from stdin: {}", e))?;
  1369→    Ok(buffer.trim_end().to_string())
  1370→}
  1371→
  1372→/// Read text from stdin, returning None if stdin is empty or a tty
  1373→pub fn jjrg_read_stdin_optional() -> Result<Option<String>, String> {
  1374→    use std::io::IsTerminal;
  1375→
  1376→    // If stdin is a terminal, no input was piped
  1377→    if std::io::stdin().is_terminal() {
  1378→        return Ok(None);
  1379→    }
  1380→
  1381→    let text = jjrg_read_stdin()?;
  1382→    if text.is_empty() {
  1383→        Ok(None)
  1384→    } else {
  1385→        Ok(Some(text))
  1386→    }
  1387→}
